mapper.update:
update base_staff
set state         = #{param.state},
    modified_by   = #{param.userId},
    modified_date = #{param.opTime}
where id = #{param.id}

update base_staff
set user_id=0
where id = #{staffId}

update base_staff
set user_id=#{userId}
where id = #{staffId}

update base_staff
set staff_code=#{staffCode}
where id = #{staffId}

