mapper.update:
update base_staff
set state= 2,
    modified_by   = #{updateUser},
    modified_date = #{modifiedDate}
where group_id = #{groupId}
  and deleted_flag=0

mapper.select:
SELECT

from base_staff as staff
left join base_staff_duty as duty on staff.id=duty.staff_id
LEFT join base_staff_type as type on duty.staff_type_id=type.id
where staff.dep_id in (

    #{depId}

)
and staff.deleted_flag=0

    and staff.user_id = #{queryParam.userId}


    and staff.id = #{staffId}


    and staff.realname like CONCAT('%',#{queryParam.staffName},'%')


    and type.biz_code in (

        #{bizCode}

    )


    and staff.employment_type = #{queryParam.employmentType}

